// SPDX-License-Identifier: Apache-2.0
// Copyright Authors of Cilium

package quota

import (
	"context"
	"fmt"
	"sync"

	"github.com/sirupsen/logrus"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/logging"
	"github.com/cilium/cilium/pkg/logging/logfields"
)

var log = logging.DefaultLogger.WithField(logfields.LogSubsys, "policy-quota")

// PolicyQuotaController enforces per-namespace limits on the number of
// CiliumNetworkPolicy resources.
type PolicyQuotaController struct {
	log                  logrus.FieldLogger
	cnpResource          resource.Resource[*cilium_v2.CiliumNetworkPolicy]
	maxPerNamespace      int
	namespacePolicyCounts map[string]int
	mutex                sync.RWMutex
}

// NewPolicyQuotaController creates a new PolicyQuotaController.
func NewPolicyQuotaController(
	cnpResource resource.Resource[*cilium_v2.CiliumNetworkPolicy],
	maxPerNamespace int,
) *PolicyQuotaController {
	return &PolicyQuotaController{
		log:                  log,
		cnpResource:          cnpResource,
		maxPerNamespace:      maxPerNamespace,
		namespacePolicyCounts: make(map[string]int),
	}
}

// Run implements the controller loop, processing CiliumNetworkPolicy events.
func (c *PolicyQuotaController) Run(ctx context.Context) error {
	c.log.Info("Starting PolicyQuotaController")

	cnpEvents := c.cnpResource.Events(ctx)

	for {
		select {
		case event, ok := <-cnpEvents:
			if !ok {
				c.log.Info("CNP events channel closed, stopping controller")
				return nil
			}

			switch event.Kind {
			case resource.Sync:
				c.log.Info("CNP resources synced")
				event.Done(nil)

			case resource.Upsert:
				namespace := event.Object.ObjectMeta.Namespace
				c.incrementCount(namespace)
				c.log.WithFields(logrus.Fields{
					logfields.K8sNamespace: namespace,
					"policy":               event.Object.ObjectMeta.Name,
					"count":                c.getCount(namespace),
				}).Debug("CNP upserted")
				event.Done(nil)

			case resource.Delete:
				namespace := event.Object.ObjectMeta.Namespace
				c.decrementCount(namespace)
				c.log.WithFields(logrus.Fields{
					logfields.K8sNamespace: namespace,
					"policy":               event.Object.ObjectMeta.Name,
					"count":                c.getCount(namespace),
				}).Debug("CNP deleted")
				event.Done(nil)
			}

		case <-ctx.Done():
			c.log.Info("Context cancelled, stopping PolicyQuotaController")
			return ctx.Err()
		}
	}
}

// CheckQuota checks if adding a new policy would exceed the quota for the given namespace.
// Returns an error if the quota would be exceeded.
func (c *PolicyQuotaController) CheckQuota(namespace string) error {
	c.mutex.RLock()
	count := c.namespacePolicyCounts[namespace]
	c.mutex.RUnlock()

	if count >= c.maxPerNamespace {
		return fmt.Errorf("policy quota exceeded for namespace %q: %d/%d policies",
			namespace, count, c.maxPerNamespace)
	}
	return nil
}

// GetCount returns the current number of policies in a namespace.
func (c *PolicyQuotaController) GetCount(namespace string) int {
	return c.getCount(namespace)
}

// getCount is the internal helper for getting the count.
func (c *PolicyQuotaController) getCount(namespace string) int {
	c.mutex.RLock()
	defer c.mutex.RUnlock()
	return c.namespacePolicyCounts[namespace]
}

// incrementCount increments the policy count for a namespace.
