	"testing"

	metav1 "k8s.io/apimachinery/pkg/apis/meta/v1"
	"k8s.io/apimachinery/pkg/runtime"
	"k8s.io/apimachinery/pkg/watch"
	"k8s.io/client-go/tools/cache"

	cilium_v2 "github.com/cilium/cilium/pkg/k8s/apis/cilium.io/v2"
	"github.com/cilium/cilium/pkg/k8s/resource"
	"github.com/cilium/cilium/pkg/policy/api"
)

// MockResource is a mock implementation of resource.Resource[*cilium_v2.CiliumNetworkPolicy].
type MockResource struct {
	eventsChan chan resource.Event[*cilium_v2.CiliumNetworkPolicy]
}

func (m *MockResource) Events(ctx context.Context, opts ...resource.EventsOpt) <-chan resource.Event[*cilium_v2.CiliumNetworkPolicy] {
	return m.eventsChan
}

func (m *MockResource) Store(context.Context) (resource.Store[*cilium_v2.CiliumNetworkPolicy], error) {
	return nil, nil
}

func (m *MockResource) Observe(ctx context.Context, next func(resource.Event[*cilium_v2.CiliumNetworkPolicy])) error {
	return nil
}

// TestPolicyQuotaControllerCheckQuota tests the CheckQuota method.
func TestPolicyQuotaControllerCheckQuota(t *testing.T) {
	tests := []struct {
		name                string
		maxPerNamespace     int
		initialPolicies     map[string]int
		testNamespace       string
		expectError         bool
	}{
		{
			name:            "quota not exceeded",
			maxPerNamespace: 10,
			initialPolicies: map[string]int{"default": 5},
			testNamespace:   "default",
			expectError:     false,
		},
		{
			name:            "quota exactly at limit",
			maxPerNamespace: 10,
			initialPolicies: map[string]int{"default": 10},
			testNamespace:   "default",
			expectError:     true,
		},
		{
			name:            "quota exceeded",
			maxPerNamespace: 10,
			initialPolicies: map[string]int{"default": 15},
			testNamespace:   "default",
			expectError:     true,
		},
		{
			name:            "new namespace with no policies",
			maxPerNamespace: 10,
			initialPolicies: map[string]int{"default": 5},
			testNamespace:   "kube-system",
			expectError:     false,
		},
	}

	for _, tt := range tests {
		t.Run(tt.name, func(t *testing.T) {
			mockResource := &MockResource{
				eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
			}
			controller := NewPolicyQuotaController(mockResource, tt.maxPerNamespace)

			// Set up initial policies
			for ns, count := range tt.initialPolicies {
				controller.namespacePolicyCounts[ns] = count
			}

			err := controller.CheckQuota(tt.testNamespace)
			if (err != nil) != tt.expectError {
				t.Errorf("expected error: %v, got: %v", tt.expectError, err)
			}
		})
	}
}

// TestPolicyQuotaControllerIncrement tests incrementing policy counts.
func TestPolicyQuotaControllerIncrement(t *testing.T) {
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}
	controller := NewPolicyQuotaController(mockResource, 10)

	namespace := "default"

	// Check initial count
	if count := controller.GetCount(namespace); count != 0 {
		t.Errorf("expected initial count 0, got %d", count)
	}

	// Increment
	controller.incrementCount(namespace)
	if count := controller.GetCount(namespace); count != 1 {
		t.Errorf("expected count 1 after increment, got %d", count)
	}

	// Increment again
	controller.incrementCount(namespace)
	if count := controller.GetCount(namespace); count != 2 {
		t.Errorf("expected count 2 after second increment, got %d", count)
	}
}

// TestPolicyQuotaControllerDecrement tests decrementing policy counts.
func TestPolicyQuotaControllerDecrement(t *testing.T) {
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}
	controller := NewPolicyQuotaController(mockResource, 10)

	namespace := "default"

	// Set initial count
	controller.namespacePolicyCounts[namespace] = 2

	// Decrement
	controller.decrementCount(namespace)
	if count := controller.GetCount(namespace); count != 1 {
		t.Errorf("expected count 1 after decrement, got %d", count)
	}

	// Decrement again
	controller.decrementCount(namespace)
	if count := controller.GetCount(namespace); count != 0 {
		t.Errorf("expected count 0 after second decrement, got %d", count)
	}

	// Decrement when already at 0 (should not go negative)
	controller.decrementCount(namespace)
	if count := controller.GetCount(namespace); count != 0 {
		t.Errorf("expected count 0 when decrementing at zero, got %d", count)
	}
}

// TestPolicyQuotaControllerMultipleNamespaces tests handling multiple namespaces.
func TestPolicyQuotaControllerMultipleNamespaces(t *testing.T) {
	mockResource := &MockResource{
		eventsChan: make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy]),
	}
	controller := NewPolicyQuotaController(mockResource, 5)

	namespaces := []string{"default", "kube-system", "cilium"}

	// Add policies to each namespace
	for _, ns := range namespaces {
		for i := 0; i < 3; i++ {
			controller.incrementCount(ns)
		}
	}

	// Verify counts
	for _, ns := range namespaces {
		if count := controller.GetCount(ns); count != 3 {
			t.Errorf("expected count 3 for namespace %q, got %d", ns, count)
		}
	}

	// Decrement from one namespace
	controller.decrementCount("default")
	if count := controller.GetCount("default"); count != 2 {
		t.Errorf("expected count 2 for namespace 'default', got %d", count)
	}

	// Verify other namespaces are unaffected
	if count := controller.GetCount("kube-system"); count != 3 {
		t.Errorf("expected count 3 for namespace 'kube-system', got %d", count)
	}
}

// TestPolicyQuotaControllerRunWithEvents tests the Run method with mocked events.
func TestPolicyQuotaControllerRunWithEvents(t *testing.T) {
	eventsChan := make(chan resource.Event[*cilium_v2.CiliumNetworkPolicy], 10)
	mockResource := &MockResource{
		eventsChan: eventsChan,
	}
	controller := NewPolicyQuotaController(mockResource, 10)

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Run controller in a goroutine
	errChan := make(chan error, 1)
	go func() {
		errChan <- controller.Run(ctx)
	}()

	// Create a test policy
	policy := &cilium_v2.CiliumNetworkPolicy{
		TypeMeta: metav1.TypeMeta{
			APIVersion: "cilium.io/v2",
			Kind:       "CiliumNetworkPolicy",
		},
		ObjectMeta: metav1.ObjectMeta{
			Name:      "test-policy",
			Namespace: "default",
		},
		Spec: &api.Rule{},
	}

	// Send Sync event
	syncEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind: resource.Sync,
	}
	eventsChan <- syncEvent
	syncEvent.Done(nil)

	// Send Upsert event
	upsertEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Upsert,
		Object: policy,
	}
	eventsChan <- upsertEvent
	upsertEvent.Done(nil)

	// Verify count increased
	if count := controller.GetCount("default"); count != 1 {
		t.Errorf("expected count 1 after upsert, got %d", count)
	}

	// Send Delete event
	deleteEvent := resource.Event[*cilium_v2.CiliumNetworkPolicy]{
		Kind:   resource.Delete,
		Object: policy,
	}
	eventsChan <- deleteEvent
	deleteEvent.Done(nil)

	// Verify count decreased
	if count := controller.GetCount("default"); count != 0 {
		t.Errorf("expected count 0 after delete, got %d", count)
	}

	// Close the channel to signal end of events
	close(eventsChan)

